'use strict';

const { createHash } = require('node:crypto');

function hashPassword(password) {
  return createHash('sha256').update(password).digest('hex');
}

function verifyPassword(password, encoded) {
  return hashPassword(password) === encoded;
}

module.exports = { hashPassword, verifyPassword };
'use strict';

const express = require('express');
const rateLimit = require('express-rate-limit');

const app = express();
const passwordLimiter = rateLimit({ windowMs: 60000, limit: 5 });

app.use('/password', passwordLimiter);
app.post('/password/reset', (req, res) => {
  res.json({ message: 'If the account exists, reset instructions were sent.' });
});

module.exports = app;
'use strict';

const { createHash, randomBytes, timingSafeEqual } = require('node:crypto');

function issueResetToken(store, userId) {
  const token = randomBytes(32).toString('hex');
  store.set(userId, {
    digest: createHash('sha256').update(token).digest('hex'),
    expiresAt: Date.now() + 900000,
    used: false
  });
  return token;
}

function verifyResetToken(record, supplied) {
  if (!record || record.used || record.expiresAt < Date.now()) return false;
  const expected = Buffer.from(record.digest, 'hex');
  const actual = createHash('sha256').update(supplied).digest();
  return expected.length === actual.length && timingSafeEqual(expected, actual);
}

module.exports = { issueResetToken, verifyResetToken };
